(1-(embedding <=> #{referenceEmbedding}::vector)) AS weight
FROM graph_entity
WHERE is_active = true
AND dimension = #{dimension}

    AND knowledge_id IN

        #{id}



    AND document_id NOT IN

        #{id}


ORDER BY weight DESC
LIMIT #{maxResults}

